import{_ as a,o as t,c as r,ag as s}from"./chunks/framework.B45ElpZ1.js";const h=JSON.parse('{"title":"Learner Mode","description":"Guided curriculum for trading and investing — chapters, interactive steps, quizzes, and broker-aware examples.","frontmatter":{"title":"Learner Mode","description":"Guided curriculum for trading and investing — chapters, interactive steps, quizzes, and broker-aware examples.","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/guides/learner"}]]},"headers":[],"relativePath":"guides/learner.md","filePath":"guides/learner.md"}'),n={name:"guides/learner.md"};function o(i,e,c,d,u,p){return t(),r("div",null,[...e[0]||(e[0]=[s(`<h1 id="learner-mode" tabindex="-1">Learner Mode <a class="header-anchor" href="#learner-mode" aria-label="Permalink to &quot;Learner Mode&quot;">​</a></h1><p>Learner is a <strong>guided curriculum</strong>, not a free-form chat. It walks through chapters in a track, presents concepts one step at a time, runs quizzes, and has you execute real workflows on TradingView, Groww, or Zerodha as interactive steps. Progress is saved automatically at the chapter and concept level — if you switch away mid-step and come back, Learner resumes where you were.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><ol><li>Reads you a short concept in plain English, without jargon dumps.</li><li>Opens the relevant page on TradingView or your broker, such as a chart, order form, or holdings view.</li><li>Asks you a question grounded in what&#39;s actually on that page.</li><li>Checks your answer, clears up confusion, then moves to the next concept.</li><li>Lets you pause anytime, ask side questions, and resume right where you left off.</li></ol><h2 id="typical-prompts" tabindex="-1">Typical prompts <a class="header-anchor" href="#typical-prompts" aria-label="Permalink to &quot;Typical prompts&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Start chapter 1</span></span>
<span class="line"><span>Continue</span></span>
<span class="line"><span>/pause        (stop the lesson, just ask questions)</span></span>
<span class="line"><span>/continue     (resume from current step)</span></span></code></pre></div><h2 id="practice-surfaces" tabindex="-1">Practice surfaces <a class="header-anchor" href="#practice-surfaces" aria-label="Permalink to &quot;Practice surfaces&quot;">​</a></h2><p>Learner combines common teaching content with surface-specific practice:</p><table tabindex="0"><thead><tr><th>Surface</th><th>What Learner uses it for</th></tr></thead><tbody><tr><td>TradingView</td><td>Chart reading, indicators, watchlists, and market-structure practice</td></tr><tr><td>Groww</td><td>Broker-aware investing and portfolio exercises</td></tr><tr><td>Zerodha</td><td>Broker-aware trading and portfolio exercises</td></tr></tbody></table><p>The teaching concept stays the same across surfaces, but the exact <code>Do</code> and <code>Check</code> instructions adapt to the platform you selected.</p><h2 id="switching-away-and-back" tabindex="-1">Switching away and back <a class="header-anchor" href="#switching-away-and-back" aria-label="Permalink to &quot;Switching away and back&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Mid-step safety</p><p>If you jump to another persona mid-lesson, your step progress is preserved. When you return to Learner, you pick up from the same interactive step.</p></div><h2 id="pausing-for-questions" tabindex="-1">Pausing for questions <a class="header-anchor" href="#pausing-for-questions" aria-label="Permalink to &quot;Pausing for questions&quot;">​</a></h2><p>Use <code>/pause</code> when you want to stop the guided flow and ask a side question. Learner keeps the current concept in memory, preserves the answer in chat, and waits until you use <code>/continue</code> before opening the next quiz or practice step.</p><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li><strong>Picking the right persona after you graduate</strong> → <a href="/wiki/guides/personas">Personas &amp; Modes</a></li><li><strong>Broker setup</strong> → <a href="./../getting-started/broker-setup">Broker Setup</a> — required for broker-aware examples</li><li><strong>Browser setup</strong> → <a href="./../getting-started/browser-setup">Browser Setup</a> — useful for TradingView and broker practice</li></ul>`,16)])])}const g=a(n,[["render",o]]);export{h as __pageData,g as default};
